import { EstimateShipping as EstimateShippingComponent } from '@/checkout/components';
import {
  Cart,
  Money as PriceModel,
  ShippingEstimate,
  TaxDisplay,
} from '@/checkout/data/models';
import { getLatestCheckoutUpdate } from '@/checkout/lib';
import { state } from '@/checkout/lib/state';
import { Price } from '@adobe-commerce/elsie/components';
import { useText } from '@adobe-commerce/elsie/i18n';
import { Container } from '@adobe-commerce/elsie/lib';
import { events } from '@adobe-commerce/event-bus';
import { useCallback, useEffect, useState } from 'preact/hooks';

interface ShippingData {
  estimated?: boolean;
  amount: PriceModel;
  amountExclTax?: PriceModel;
  amountInclTax?: PriceModel;
}

export interface EstimateShippingProps {
  active?: boolean;
}

export const EstimateShipping: Container<EstimateShippingProps> = ({
  active = true,
}) => {
  const [data, setData] = useState<ShippingData | null | undefined>();

  const isFreeShipping = data?.amount.value === 0;
  const shippingDisplay = state.config?.shoppingCartDisplaySetting.shipping;
  const taxExcluded = shippingDisplay === TaxDisplay.INCLUDING_EXCLUDING_TAX;
  const taxIncluded = shippingDisplay === TaxDisplay.INCLUDING_TAX;

  const translations = useText({
    freeShipping: 'Checkout.EstimateShipping.freeShipping',
    taxToBeDetermined: 'Checkout.EstimateShipping.taxToBeDetermined',
    label: 'Checkout.EstimateShipping.label',
    estimated: 'Checkout.EstimateShipping.estimated',
  });

  const handleCheckoutData = useCallback((data: Cart | null) => {
    const isEmptyCart = !data || data.isEmpty;
    const isVirtualCart = Boolean(data?.isVirtual);

    if (isEmptyCart || isVirtualCart) {
      setData(null);
      return;
    }

    const primaryAddress = data.shippingAddresses?.[0];

    if (!primaryAddress) {
      return;
    }

    const shippingMethod = primaryAddress?.selectedShippingMethod;

    if (!shippingMethod) {
      setData(null);
      return;
    }

    const { amount, amountExclTax, amountInclTax } = shippingMethod;
    setData({ estimated: false, amount, amountExclTax, amountInclTax });
  }, []);

  const handleShippingEstimate = useCallback((estimation: ShippingEstimate) => {
    let shippingData: ShippingData | null = null;

    if (estimation.shippingMethod) {
      const shippingMethod = estimation.shippingMethod;

      shippingData = {
        estimated: true,
        amount: shippingMethod.amount,
        amountExclTax: shippingMethod.amountExclTax,
        amountInclTax: shippingMethod.amountInclTax,
      };
    }

    setData(shippingData);
  }, []);

  useEffect(() => {
    if (!active) return;

    const onShippingEstimate = events.on(
      'shipping/estimate',
      handleShippingEstimate,
      { eager: true }
    );

    return () => {
      onShippingEstimate?.off();
    };
  }, [active, handleShippingEstimate]);

  useEffect(() => {
    if (!active) return;

    const pastUpdate = getLatestCheckoutUpdate();

    if (pastUpdate) {
      handleCheckoutData(pastUpdate);
      return;
    }

    const onCheckoutInit = events.on(
      'checkout/initialized',
      handleCheckoutData,
      { eager: true }
    );

    return () => {
      onCheckoutInit?.off();
    };
  }, [active, handleCheckoutData]);

  useEffect(() => {
    if (!active) return;

    const onCheckoutUpdated = events.on(
      'checkout/updated',
      handleCheckoutData,
      { eager: false }
    );

    return () => {
      onCheckoutUpdated?.off();
    };
  }, [active, handleCheckoutData]);

  const renderPrice = () => {
    if (isFreeShipping) {
      return (
        <span data-testid="free-shipping">{translations.freeShipping}</span>
      );
    }

    if (taxIncluded && data?.amountInclTax) {
      return (
        <Price
          amount={data.amountInclTax.value}
          currency={data.amountInclTax.currency}
          data-testid="shipping"
        />
      );
    }

    return (
      <Price
        amount={data?.amount.value}
        currency={data?.amount.currency}
        data-testid="shipping"
      />
    );
  };

  const renderPriceExclTax = () => {
    if (!data?.amountExclTax)
      return <span>{translations.taxToBeDetermined}</span>;

    return (
      <Price
        amount={data.amountExclTax.value}
        currency={data.amountExclTax.currency}
        data-testid="shipping-excluding-tax"
      />
    );
  };

  const renderLabel = () => {
    const label = data?.estimated ? translations.estimated : translations.label;
    return <span data-testid="estimate-shipping-label">{label}</span>;
  };

  return (
    <EstimateShippingComponent
      initialized={data !== undefined}
      label={renderLabel()}
      price={renderPrice()}
      priceExclTax={renderPriceExclTax()}
      taxExcluded={taxExcluded && !isFreeShipping}
      taxIncluded={taxIncluded && !isFreeShipping}
      visible={active && data !== null}
    />
  );
};
